import { describe, expect, test } from 'vitest';

import * as maybe from 'true-myth/maybe';
import * as result from 'true-myth/result';
import * as task from 'true-myth/task';
import * as toolbelt from 'true-myth/toolbelt';

describe('collection combinators', () => {
  test('Maybe and Result iterators yield only successful values', () => {
    expect([...maybe.just(1)]).toEqual([1]);
    expect([...maybe.nothing<number>()]).toEqual([]);
    expect([...result.ok(1)]).toEqual([1]);
    expect([...result.err<number, string>('no')]).toEqual([]);
  });

  test('Maybe and Result sequence and traverse short-circuit iterables', () => {
    let maybeAdvanced = 0;
    function* maybes() {
      maybeAdvanced++;
      yield maybe.just(1);
      maybeAdvanced++;
      yield maybe.nothing<number>();
      maybeAdvanced++;
      yield maybe.just(3);
    }
    expect(maybe.sequence(maybes())).toEqual(maybe.nothing());
    expect(maybeAdvanced).toBe(2);
    expect(
      maybe.traverse((n: number) => (n < 2 ? maybe.just(n) : maybe.nothing()))([1, 2, 3])
    ).toEqual(maybe.nothing());

    let resultAdvanced = 0;
    function* results() {
      resultAdvanced++;
      yield result.ok<number, string>(1);
      resultAdvanced++;
      yield result.err<number, string>('no');
      resultAdvanced++;
      yield result.ok<number, string>(3);
    }
    expect(result.sequence(results())).toEqual(result.err('no'));
    expect(resultAdvanced).toBe(2);
    expect(result.traverse([1, 2, 3], (n) => (n < 2 ? result.ok(n) : result.err('no')))).toEqual(
      result.err('no')
    );
  });

  test('Maybe collection helpers', () => {
    expect(maybe.zipWith(maybe.just(2), maybe.just(3), (a, b) => a + b)).toEqual(maybe.just(5));
    expect(maybe.compact([maybe.just(1), maybe.nothing<number>(), maybe.just(3)])).toEqual([1, 3]);
    expect(maybe.filterMap([1, 2, 3], (n) => (n % 2 ? maybe.just(n) : maybe.nothing()))).toEqual([
      1, 3,
    ]);
    expect(maybe.firstJust([maybe.nothing<number>(), maybe.just(2)])).toEqual(maybe.just(2));
  });

  test('Result collection helpers', () => {
    expect(result.zip(result.ok<number, string>(1), result.ok<number, string>(2))).toEqual(
      result.ok([1, 2])
    );
    expect(result.zipWith(result.ok(2), result.ok(3), (a, b) => a + b)).toEqual(result.ok(5));
    expect(
      result.partition([result.ok<number, string>(1), result.err<number, string>('no')])
    ).toEqual([[1], ['no']]);
  });

  test('Task async iteration yields exactly its Result', async () => {
    const oks = [];
    for await (const value of task.resolve(1)) oks.push(value);
    expect(oks).toEqual([result.ok(1)]);
    const errs = [];
    for await (const value of task.reject<number, string>('no')) errs.push(value);
    expect(errs).toEqual([result.err('no')]);
  });

  test('Task serial traversal stops before the next task and retryN retries exactly n times', async () => {
    const seen: number[] = [];
    const serial = task.traverseSerial([1, 2, 3], (n) => {
      seen.push(n);
      return n === 2 ? task.reject<number, string>('no') : task.resolve<number, string>(n);
    });
    expect(await serial).toEqual(result.err('no'));
    expect(seen).toEqual([1, 2]);

    let attempts = 0;
    const retried = task.retryN(2, () => {
      attempts++;
      return attempts === 3 ? task.resolve<number, string>(3) : task.reject<number, string>('no');
    });
    expect(await retried).toEqual(result.ok(3));
    expect(attempts).toBe(3);
  });

  test('Task zip, traverse, and taps preserve outcomes', async () => {
    expect(
      await task.zip(task.resolve<number, string>(1), task.resolve<number, string>(2))
    ).toEqual(result.ok([1, 2]));
    expect(await task.traverse([1, 2], (n) => task.resolve<number, string>(n))).toEqual(
      result.ok([1, 2])
    );
    const seen: number[] = [];
    const errors: string[] = [];
    expect(await task.tap(task.resolve<number, string>(1), (n) => seen.push(n))).toEqual(
      result.ok(1)
    );
    expect(
      await task.tapRejected(task.reject<number, string>('no'), (e) => errors.push(e))
    ).toEqual(result.err('no'));
    expect(seen).toEqual([1]);
    expect(errors).toEqual(['no']);
  });

  test('toolbelt converts Nothing to the supplied Err value', () => {
    expect(toolbelt.sequenceMaybeAsResult('missing', [maybe.just(1), maybe.just(2)])).toEqual(
      result.ok([1, 2])
    );
    expect(
      toolbelt.traverseMaybeAsResult('missing', [1, 2], (n) =>
        n === 1 ? maybe.just(n) : maybe.nothing()
      )
    ).toEqual(result.err('missing'));
    expect(toolbelt.zipMaybeAsResult('missing')(maybe.just(1), maybe.nothing<number>())).toEqual(
      result.err('missing')
    );
  });
});

